mapper.update:
UPDATE sys_user
phone = #{phone,jdbcType=VARCHAR}, name = #{name,jdbcType=VARCHAR}, email = #{email,jdbcType=VARCHAR}, avatar = #{avatar,jdbcType=VARCHAR}, gender = #{gender,jdbcType=TINYINT}, birthday = #{birthday,jdbcType=DATE}, store_id = #{storeId,jdbcType=BIGINT}, employee_no = #{employeeNo,jdbcType=VARCHAR}, status = #{status,jdbcType=TINYINT}, password = #{password,jdbcType=VARCHAR}, updated_time = NOW()
WHERE id = #{id,jdbcType=BIGINT}

mapper.select:
SELECT u.id, u.phone, u.name, u.email, u.avatar, u.gender, u.birthday, u.store_id, u.employee_no, u.status, u.login_count, u.last_login_time, u.last_login_ip, u.created_time, u.updated_time, r.role_code, r.role_name FROM sys_user u LEFT JOIN sys_user_role ur ON u.id = ur.user_id LEFT JOIN sys_role r ON ur.role_id = r.id WHERE r.role_code != 'SYSTEM_ADMIN'
AND u.name LIKE CONCAT('%', #{name}, '%')
AND u.phone LIKE CONCAT('%', #{phone}, '%')
AND u.store_id = #{storeId}
AND r.role_name = #{roleName}
AND u.status = #{status}
ORDER BY ${orderBy}
ORDER BY u.created_time DESC
